import React from 'react';
import swe1 from '../assets/swe1.jpg';
import swe2 from '../assets/swe2.jpg';
import swe3 from '../assets/swe3.jpg';
import dsc1 from '../assets/dsc1.jpg';
import dsc2 from '../assets/dsc2.jpg';
import dsc3 from '../assets/dsc3.jpg';
import spartan from '../assets/spartan.jpg';
import spartan2 from '../assets/spartan2.jpg';
import img4361 from '../assets/img4361.jpg';
import img4362 from '../assets/img4362.jpg';
import img4363 from '../assets/img4363.jpg';
import './Involvement.css';

const photos = [
  { photo: dsc1,     position: 'center', org: 'Responsible Computing Club', roles: ['Mozilla & Firefox Ambassador', 'VP of External Affairs', 'Community Engagement Lead'] },
  { photo: dsc2,     position: 'center', org: 'Responsible Computing Club', roles: ['Mozilla & Firefox Ambassador', 'VP of External Affairs', 'Community Engagement Lead'] },
  { photo: dsc3,     position: 'center', org: 'Responsible Computing Club', roles: ['Mozilla & Firefox Ambassador', 'VP of External Affairs', 'Community Engagement Lead'] },
  //{ photo: swe1,     position: 'center ', org: 'Society of Women Engineers',  roles: ['Alumni Relations Committee Chair', 'Mentorship Committee Chair', 'SWE++ Program Volunteer'] },
  //{ photo: swe2,     position: 'center', org: 'Society of Women Engineers',  roles: ['Alumni Relations Committee Chair', 'Mentorship Committee Chair', 'SWE++ Program Volunteer'] },
  //{ photo: swe3,     position: 'center', org: 'Society of Women Engineers',  roles: ['Alumni Relations Committee Chair', 'Mentorship Committee Chair', 'SWE++ Program Volunteer'] },
  { photo: img4361,  position: 'center 55%', org: 'CAPISE',                      roles: ['Asian Pacific Islander Empower Mentor'] },
  { photo: spartan,  position: 'center 30%', org: 'Spartan Racing Formula SAE',  roles: ['Business Team Intern'] },
  { photo: spartan2, position: 'center', org: 'Spartan Racing Formula SAE',  roles: ['Business Team Intern'] },
];

export default function Involvement() {
  return (
    <section id="involvement" className="involvement-section">
      <div className="inner">
        <span className="section-label reveal">On Campus</span>
        <h2 className="section-title reveal d1">Involvement</h2>
      </div>
      <CircularGallery items={items} bend={1} scrollSpeed={2} scrollEase={0.05} />
    </section>
  );
}
